INSERT INTO news (id, title, excerpt, content, image, tag, date) VALUES (1, 'ISCL Hosts Grand Official Jersey Launch & Team Owners Introduction Ceremony as Season 03 Registrations Open', 'The road to the championship builds momentum as the league unveils its vibrant new team jerseys and introduces the visionaries backing the franchises.', 'The road to the championship builds momentum as the league unveils its vibrant new team jerseys and introduces the visionaries backing the franchises.', '/images/gully_cricket.png', 'Press Release', '2026-06-03');
INSERT INTO news (id, title, excerpt, content, image, tag, date) VALUES (2, 'Inaugural ISCL Season Concludes as a Historic Milestone for Indian Softball Cricket; Punjab Crowned Champions', 'Punjab lifts the trophy after a dramatic win under the stadium floodlights, sealing a legendary campaign.', 'Punjab lifts the trophy after a dramatic win under the stadium floodlights, sealing a legendary campaign.', '/images/cricket_stadium_night.png', 'Match Report', '2026-05-20');
INSERT INTO news (id, title, excerpt, content, image, tag, date) VALUES (3, 'Suresh Raina Champions Grassroots Talent as Official Ambassador of the ISCL', 'Former Indian cricket star and revered ''Mr. IPL'' aligns with Founder & President Dr. Gangadhar Raju to provide an incredible platform.', 'Former Indian cricket star and revered ''Mr. IPL'' aligns with Founder & President Dr. Gangadhar Raju to provide an incredible platform.', '/images/suresh_raina.png', 'Interview', '2026-06-01');
INSERT INTO news (id, title, excerpt, content, image, tag, date) VALUES (4, 'Harbhajan Singh Joins Elite Panel to Mentor Gully Cricketers', 'The legendary spinner breaks down what it takes to leap from street pitches to grand stadiums.', 'The legendary spinner breaks down what it takes to leap from street pitches to grand stadiums.', '/images/harbhajan.png', 'Interview', '2026-06-02');
